  1→//! Push notification support for PWA clients.
  2→//!
  3→//! Handles VAPID key generation/storage, subscription management, and sending
  4→//! push notifications when the LLM responds while the user is not actively
  5→//! viewing the chat.
  6→
  7→use {
  8→    anyhow::{Context, Result},
  9→    base64::Engine,
 10→    chrono::{DateTime, Utc},
 11→    p256::{
 12→        PublicKey, ecdsa::SigningKey, elliptic_curve::rand_core::OsRng, pkcs8::EncodePrivateKey,
 13→    },
 14→    serde::{Deserialize, Serialize},
 15→    std::{path::PathBuf, sync::Arc},
 16→    tokio::sync::RwLock,
 17→    tracing::{debug, error, info, warn},
 18→    web_push::{
 19→        ContentEncoding, SubscriptionInfo, VapidSignatureBuilder, WebPushClient,
 20→        WebPushMessageBuilder,
 21→    },
 22→};
 23→
 24→/// VAPID keys for push notifications.
 25→#[derive(Debug, Clone, Serialize, Deserialize)]
 26→pub struct VapidKeys {
 27→    /// Base64 URL-safe encoded public key (for the browser).
 28→    pub public_key: String,
 29→    /// PEM-encoded private key (for signing).
 30→    pub private_key_pem: String,
 31→}
 32→
 33→/// A push subscription from a browser.
 34→#[derive(Debug, Clone, Serialize, Deserialize)]
 35→pub struct PushSubscription {
 36→    /// The push endpoint URL.
 37→    pub endpoint: String,
 38→    /// The p256dh key (base64 URL-safe encoded).
 39→    pub p256dh: String,
 40→    /// The auth secret (base64 URL-safe encoded).
 41→    pub auth: String,
 42→    /// User agent string (for debugging).
 43→    #[serde(skip_serializing_if = "Option::is_none")]
 44→    pub user_agent: Option<String>,
 45→    /// Client IP address.
 46→    #[serde(skip_serializing_if = "Option::is_none")]
 47→    pub ip_address: Option<String>,
 48→    /// When the subscription was created.
 49→    pub created_at: DateTime<Utc>,
 50→}
 51→
 52→/// Payload for a push notification.
 53→#[derive(Debug, Clone, Serialize)]
 54→pub struct PushPayload {
 55→    /// Notification title.
 56→    pub title: String,
 57→    /// Notification body text.
 58→    pub body: String,
 59→    /// URL to open when clicked.
 60→    #[serde(skip_serializing_if = "Option::is_none")]
 61→    pub url: Option<String>,
 62→    /// Session key for deduplication.
 63→    #[serde(rename = "sessionKey", skip_serializing_if = "Option::is_none")]
 64→    pub session_key: Option<String>,
 65→}
 66→
 67→/// Stored push data (VAPID keys + subscriptions).
 68→#[derive(Debug, Default, Serialize, Deserialize)]
 69→struct PushStore {
 70→    #[serde(skip_serializing_if = "Option::is_none")]
 71→    vapid: Option<VapidKeys>,
 72→    #[serde(default)]
 73→    subscriptions: Vec<PushSubscription>,
 74→}
 75→
 76→/// Push notification service.
 77→pub struct PushService {
 78→    store: RwLock<PushStore>,
 79→    store_path: PathBuf,
 80→    client: Box<dyn WebPushClient + Send + Sync>,
 81→}
 82→
 83→impl PushService {
 84→    /// Create a new push service, loading or generating VAPID keys.
 85→    pub async fn new(data_dir: &std::path::Path) -> Result<Arc<Self>> {
 86→        let store_path = data_dir.join("push.json");
 87→        let store = if store_path.exists() {
 88→            let content = tokio::fs::read_to_string(&store_path)
 89→                .await
 90→                .context("Failed to read push store")?;
 91→            serde_json::from_str(&content).unwrap_or_default()
 92→        } else {
 93→            PushStore::default()
 94→        };
 95→
 96→        let client: Box<dyn WebPushClient + Send + Sync> =
 97→            Box::new(web_push::IsahcWebPushClient::new()?);
 98→
 99→        let service = Arc::new(Self {
100→            store: RwLock::new(store),
101→            store_path,
102→            client,
103→        });
104→
105→        // Generate VAPID keys if not present.
106→        if service.store.read().await.vapid.is_none() {
107→            service.generate_vapid_keys().await?;
108→        }
109→
110→        Ok(service)
111→    }
112→
113→    /// Generate new VAPID keys and save them.
114→    async fn generate_vapid_keys(&self) -> Result<()> {
115→        info!("Generating new VAPID keys for push notifications");
116→
117→        // Generate a new ECDSA P-256 key pair.
118→        let signing_key = SigningKey::random(&mut OsRng);
119→        let public_key = PublicKey::from(signing_key.verifying_key());
120→
121→        // Get the public key in uncompressed point format and encode as base64 URL-safe.
122→        let public_key_bytes = public_key.to_sec1_bytes();
123→        let public_key_b64 =
124→            base64::engine::general_purpose::URL_SAFE_NO_PAD.encode(&public_key_bytes);
125→
126→        // Get the private key as PEM.
127→        let private_key_pem = signing_key
128→            .to_pkcs8_pem(p256::pkcs8::LineEnding::LF)
129→            .context("Failed to encode private key as PEM")?;
130→
131→        let keys = VapidKeys {
132→            public_key: public_key_b64,
133→            private_key_pem: private_key_pem.to_string(),
134→        };
135→
136→        {
137→            let mut store = self.store.write().await;
138→            store.vapid = Some(keys);
139→        }
140→
141→        self.save_store().await?;
142→        info!("VAPID keys generated and saved");
143→        Ok(())
144→    }
145→
146→    /// Get the VAPID public key for clients.
147→    pub async fn vapid_public_key(&self) -> Option<String> {
148→        self.store
149→            .read()
150→            .await
151→            .vapid
152→            .as_ref()
153→            .map(|v| v.public_key.clone())
154→    }
155→
156→    /// Add a new push subscription.
157→    pub async fn add_subscription(&self, sub: PushSubscription) -> Result<()> {
158→        {
159→            let mut store = self.store.write().await;
160→            // Remove any existing subscription with the same endpoint.
161→            store.subscriptions.retain(|s| s.endpoint != sub.endpoint);
162→            store.subscriptions.push(sub);
163→        }
164→        self.save_store().await?;
165→        info!("Added push subscription");
166→        Ok(())
167→    }
168→
169→    /// Remove a subscription by endpoint.
170→    pub async fn remove_subscription(&self, endpoint: &str) -> Result<()> {
171→        {
172→            let mut store = self.store.write().await;
173→            let before = store.subscriptions.len();
174→            store.subscriptions.retain(|s| s.endpoint != endpoint);
175→            if store.subscriptions.len() < before {
176→                info!("Removed push subscription");
177→            }
178→        }
179→        self.save_store().await?;
180→        Ok(())
181→    }
182→
183→    /// Get the number of active subscriptions.
184→    pub async fn subscription_count(&self) -> usize {
185→        self.store.read().await.subscriptions.len()
186→    }
187→
188→    /// Get all subscriptions (for admin display).
189→    pub async fn list_subscriptions(&self) -> Vec<PushSubscription> {
190→        self.store.read().await.subscriptions.clone()
191→    }
192→
193→    /// Send a push notification to all subscriptions.
194→    pub async fn send_to_all(&self, payload: &PushPayload) -> Result<usize> {
195→        let (vapid, subscriptions) = {
196→            let store = self.store.read().await;
197→            (store.vapid.clone(), store.subscriptions.clone())
198→        };
199→
200→        let Some(vapid) = vapid else {
201→            warn!("No VAPID keys configured, cannot send push notifications");
202→            return Ok(0);
203→        };
204→
205→        if subscriptions.is_empty() {
206→            debug!("No push subscriptions, skipping notification");
207→            return Ok(0);
208→        }
209→
210→        let payload_json = serde_json::to_vec(payload)?;
211→        let mut sent = 0;
212→        let mut failed_endpoints = Vec::new();
213→
214→        for sub in &subscriptions {
215→            match self.send_to_subscription(&vapid, sub, &payload_json).await {
216→                Ok(()) => sent += 1,
217→                Err(e) => {
218→                    error!(endpoint = %sub.endpoint, error = %e, "Failed to send push notification");
219→                    // If the subscription is invalid (410 Gone), mark for removal.
220→                    if e.to_string().contains("410") || e.to_string().contains("Gone") {
221→                        failed_endpoints.push(sub.endpoint.clone());
222→                    }
223→                },
224→            }
225→        }
226→
227→        // Clean up invalid subscriptions.
228→        if !failed_endpoints.is_empty() {
229→            let mut store = self.store.write().await;
230→            store
231→                .subscriptions
232→                .retain(|s| !failed_endpoints.contains(&s.endpoint));
233→            drop(store);
234→            let _ = self.save_store().await;
235→        }
236→
237→        Ok(sent)
238→    }
239→
240→    /// Send a push notification to a single subscription.
241→    async fn send_to_subscription(
242→        &self,
243→        vapid: &VapidKeys,
244→        sub: &PushSubscription,
245→        payload: &[u8],
246→    ) -> Result<()> {
247→        let subscription_info = SubscriptionInfo {
248→            endpoint: sub.endpoint.clone(),
249→            keys: web_push::SubscriptionKeys {
250→                p256dh: sub.p256dh.clone(),
251→                auth: sub.auth.clone(),
252→            },
253→        };
254→
255→        let sig_builder =
256→            VapidSignatureBuilder::from_pem(vapid.private_key_pem.as_bytes(), &subscription_info)?
257→                .build()?;
258→
259→        let mut builder = WebPushMessageBuilder::new(&subscription_info);
260→        builder.set_payload(ContentEncoding::Aes128Gcm, payload);
261→        builder.set_vapid_signature(sig_builder);
262→
263→        let message = builder.build()?;
264→        self.client.send(message).await?;
265→
266→        debug!(endpoint = %sub.endpoint, "Sent push notification");
267→        Ok(())
268→    }
269→
270→    /// Save the store to disk.
271→    async fn save_store(&self) -> Result<()> {
272→        let store = self.store.read().await;
273→        let content = serde_json::to_string_pretty(&*store)?;
274→        tokio::fs::write(&self.store_path, content).await?;
275→        Ok(())
276→    }
277→}
278→
279→/// Send a push notification to all subscribers.
280→pub async fn send_push_notification(
281→    push_service: &Arc<PushService>,
282→    title: &str,
283→    body: &str,
284→    url: Option<&str>,
285→    session_key: Option<&str>,
286→) -> Result<usize> {
287→    let payload = PushPayload {
288→        title: title.to_string(),
289→        body: body.to_string(),
290→        url: url.map(String::from),
291→        session_key: session_key.map(String::from),
292→    };
293→
294→    push_service.send_to_all(&payload).await
295→}
296→

