   1→//! Channel delivery, TTS, push notifications, tool status, screenshots, documents, and location.
   2→
   3→use std::{collections::HashSet, sync::Arc, time::Duration};
   4→
   5→use {
   6→    serde::{Deserialize, Serialize},
   7→    serde_json::Value,
   8→    tracing::{debug, info, warn},
   9→};
  10→
  11→use moltis_sessions::store::SessionStore;
  12→
  13→use crate::{
  14→    agent_loop::ChannelReplyTargetKey, compaction_run, error, runtime::ChatRuntime, types::*,
  15→};
  16→
  17→#[cfg(feature = "push-notifications")]
  18→pub(crate) async fn send_chat_push_notification(
  19→    state: &Arc<dyn ChatRuntime>,
  20→    session_key: &str,
  21→    text: &str,
  22→) {
  23→    // Create a short summary of the response (first 100 chars)
  24→    let summary = if text.len() > 100 {
  25→        format!("{}…", truncate_at_char_boundary(text, 100))
  26→    } else {
  27→        text.to_string()
  28→    };
  29→
  30→    let title = "Message received";
  31→    let url = format!("/chat/{session_key}");
  32→
  33→    match state
  34→        .send_push_notification(title, &summary, Some(&url), Some(session_key))
  35→        .await
  36→    {
  37→        Ok(sent) => {
  38→            tracing::info!(sent, "push notification sent");
  39→        },
  40→        Err(e) => {
  41→            tracing::warn!("failed to send push notification: {e}");
  42→        },
  43→    }
  44→}
  45→
  46→/// Drain any pending channel reply targets for a session and send the
  47→/// response text back to each originating channel via outbound.
  48→/// Each delivery runs in its own spawned task so slow network calls
  49→/// don't block each other or the chat pipeline.
  50→pub(crate) async fn deliver_channel_replies(
  51→    state: &Arc<dyn ChatRuntime>,
  52→    session_key: &str,
  53→    text: &str,
  54→    desired_reply_medium: ReplyMedium,
  55→    streamed_target_keys: &HashSet<ChannelReplyTargetKey>,
  56→) {
  57→    let drained_targets = state.drain_channel_replies(session_key).await;
  58→    let mut targets = Vec::with_capacity(drained_targets.len());
  59→    let mut streamed_targets = Vec::new();
  60→    // When the reply medium is voice we must still deliver TTS audio even if
  61→    // the text was already streamed — skip the stream dedupe entirely.
  62→    if desired_reply_medium != ReplyMedium::Voice && !streamed_target_keys.is_empty() {
  63→        for target in drained_targets {
  64→            let key = ChannelReplyTargetKey::from(&target);
  65→            if streamed_target_keys.contains(&key) {
  66→                streamed_targets.push(target);
  67→            } else {
  68→                targets.push(target);
  69→            }
  70→        }
  71→    } else {
  72→        targets = drained_targets;
  73→    }
  74→    let is_channel_session = session_key.starts_with("telegram:")
  75→        || session_key.starts_with("msteams:")
  76→        || session_key.starts_with("discord:");
  77→    if targets.is_empty() && streamed_targets.is_empty() {
  78→        let _ = state.drain_channel_status_log(session_key).await;
  79→        if is_channel_session {
  80→            info!(
  81→                session_key,
  82→                text_len = text.len(),
  83→                streamed_count = streamed_target_keys.len(),
  84→                "channel reply delivery skipped: no pending targets after stream dedupe"
  85→            );
  86→        }
  87→        return;
  88→    }
  89→    if text.is_empty() {
  90→        let _ = state.drain_channel_status_log(session_key).await;
  91→        if is_channel_session {
  92→            info!(
  93→                session_key,
  94→                target_count = targets.len() + streamed_targets.len(),
  95→                "channel reply delivery skipped: empty response text"
  96→            );
  97→        }
  98→        return;
  99→    }
 100→    if is_channel_session {
 101→        info!(
 102→            session_key,
 103→            target_count = targets.len(),
 104→            text_len = text.len(),
 105→            reply_medium = ?desired_reply_medium,
 106→            "channel reply delivery starting"
 107→        );
 108→    }
 109→    let outbound = match state.channel_outbound() {
 110→        Some(o) => o,
 111→        None => {
 112→            if is_channel_session {
 113→                info!(
 114→                    session_key,
 115→                    target_count = targets.len(),
 116→                    "channel reply delivery skipped: outbound unavailable"
 117→                );
 118→            }
 119→            return;
 120→        },
 121→    };
 122→    // Drain buffered status log entries to build a logbook suffix.
 123→    let status_log = state.drain_channel_status_log(session_key).await;
 124→    let logbook_html = format_logbook_html(&status_log);
 125→    if !streamed_targets.is_empty() && !logbook_html.is_empty() {
 126→        send_channel_logbook_follow_up_to_targets(
 127→            Arc::clone(&outbound),
 128→            streamed_targets,
 129→            &logbook_html,
 130→        )
 131→        .await;
 132→    }
 133→    if targets.is_empty() {
 134→        if is_channel_session {
 135→            info!(
 136→                session_key,
 137→                text_len = text.len(),
 138→                streamed_count = streamed_target_keys.len(),
 139→                "channel reply delivery completed via stream-only targets"
 140→            );
 141→        }
 142→        return;
 143→    }
 144→    deliver_channel_replies_to_targets(
 145→        outbound,
 146→        targets,
 147→        session_key,
 148→        text,
 149→        Arc::clone(state),
 150→        desired_reply_medium,
 151→        status_log,
 152→        streamed_target_keys,
 153→    )
 154→    .await;
 155→}
 156→
 157→/// Format buffered status log entries into a Telegram expandable blockquote HTML.
 158→/// Returns an empty string if there are no entries.
 159→fn format_logbook_html(entries: &[String]) -> String {
 160→    if entries.is_empty() {
 161→        return String::new();
 162→    }
 163→    let mut html = String::from("<blockquote expandable>\n\u{1f4cb} <b>Activity log</b>\n");
 164→    for entry in entries {
 165→        // Escape HTML entities in the entry text.
 166→        let escaped = entry
 167→            .replace('&', "&amp;")
 168→            .replace('<', "&lt;")
 169→            .replace('>', "&gt;");
 170→        html.push_str(&format!("\u{2022} {escaped}\n"));
 171→    }
 172→    html.push_str("</blockquote>");
 173→    html
 174→}
 175→
 176→async fn send_channel_logbook_follow_up_to_targets(
 177→    outbound: Arc<dyn moltis_channels::plugin::ChannelOutbound>,
 178→    targets: Vec<moltis_channels::ChannelReplyTarget>,
 179→    logbook_html: &str,
 180→) {
 181→    if targets.is_empty() || logbook_html.is_empty() {
 182→        return;
 183→    }
 184→
 185→    let html = logbook_html.to_string();
 186→    let mut tasks = Vec::with_capacity(targets.len());
 187→    for target in targets {
 188→        let outbound = Arc::clone(&outbound);
 189→        let html = html.clone();
 190→        let to = target.outbound_to().into_owned();
 191→        tasks.push(tokio::spawn(async move {
 192→            if let Err(e) = outbound
 193→                .send_html(&target.account_id, &to, &html, None)
 194→                .await
 195→            {
 196→                warn!(
 197→                    account_id = target.account_id,
 198→                    chat_id = target.chat_id,
 199→                    thread_id = target.thread_id.as_deref().unwrap_or("-"),
 200→                    "failed to send logbook follow-up: {e}"
 201→                );
 202→            }
 203→        }));
 204→    }
 205→
 206→    for task in tasks {
 207→        if let Err(e) = task.await {
 208→            warn!(error = %e, "channel logbook follow-up task join failed");
 209→        }
 210→    }
 211→}
 212→
 213→fn format_channel_retry_message(error_obj: &Value, retry_after: Duration) -> String {
 214→    let retry_secs = ((retry_after.as_millis() as u64).saturating_add(999) / 1_000).max(1);
 215→    if error_obj.get("type").and_then(|v| v.as_str()) == Some("rate_limit_exceeded") {
 216→        format!("⏳ Provider rate limited. Retrying in {retry_secs}s.")
 217→    } else {
 218→        format!("⏳ Temporary provider issue. Retrying in {retry_secs}s.")
 219→    }
 220→}
 221→
 222→fn format_channel_error_message(error_obj: &Value) -> String {
 223→    let title = error_obj
 224→        .get("title")
 225→        .and_then(|v| v.as_str())
 226→        .or_else(|| match error_obj.get("type").and_then(|v| v.as_str()) {
 227→            Some("message_rejected") => Some("Message rejected"),
 228→            _ => None,
 229→        })
 230→        .unwrap_or("Request failed");
 231→    let detail = error_obj
 232→        .get("detail")
 233→        .and_then(|v| v.as_str())
 234→        .or_else(|| error_obj.get("message").and_then(|v| v.as_str()))
 235→        .unwrap_or("Please try again.");
 236→    format!("⚠️ {title}: {detail}")
 237→}
 238→
 239→/// Format a user-facing notice announcing that a session was compacted.
 240→///
 241→/// Shown verbatim to channel users (Telegram, Discord, WhatsApp, etc.) and
 242→/// kept short so small mobile clients don't wrap the whole thing.
 243→///
 244→/// When `include_settings_hint` is false, the "Change chat.compaction.mode…"
 245→/// footer is omitted so users who have set
 246→/// `chat.compaction.show_settings_hint = false` don't see the repetitive
 247→/// hint on every compaction. Mode + token lines are always included.
 248→/// The LLM retry path never sees this text regardless.
 249→fn format_channel_compaction_notice(
 250→    outcome: &compaction_run::CompactionOutcome,
 251→    include_settings_hint: bool,
 252→) -> String {
 253→    let mode_label = match outcome.effective_mode {
 254→        moltis_config::CompactionMode::Deterministic => "Deterministic",
 255→        moltis_config::CompactionMode::RecencyPreserving => "Recency preserving",
 256→        moltis_config::CompactionMode::Structured => "Structured",
 257→        moltis_config::CompactionMode::LlmReplace => "LLM replace",
 258→    };
 259→    let total = outcome.total_tokens();
 260→    let token_line = if total == 0 {
 261→        // Any strategy that made no LLM calls ends up here: Deterministic,
 262→        // RecencyPreserving, or a Structured run that fell back to
 263→        // recency_preserving before the LLM call landed. Report the
 264→        // actual effective mode so users don't see "deterministic
 265→        // strategy" when they picked recency_preserving.
 266→        format!(
 267→            "No LLM tokens used ({} strategy)",
 268→            mode_label.to_lowercase()
 269→        )
 270→    } else {
 271→        format!(
 272→            "Used {total} tokens ({input} in + {output} out)",
 273→            total = total,
 274→            input = outcome.input_tokens,
 275→            output = outcome.output_tokens,
 276→        )
 277→    };
 278→    let body = format!(
 279→        "🧹 Conversation compacted\n\
 280→         Mode: {mode_label}\n\
 281→         {token_line}",
 282→    );
 283→    if include_settings_hint {
 284→        format!("{body}\n{hint}", hint = compaction_run::SETTINGS_HINT)
 285→    } else {
 286→        body
 287→    }
 288→}
 289→
 290→/// Send a silent "session compacted" notice to pending channel targets
 291→/// without draining them.
 292→///
 293→/// Mirrors [`send_retry_status_to_channels`]: the targets are *peeked*,
 294→/// not drained, so the in-flight agent run can still deliver its final
 295→/// reply to them afterward. Uses `send_text_silent` so the channel
 296→/// integration doesn't count it toward user-visible interactive replies
 297→/// (no TTS, no delivery receipts beyond the channel's own).
 298→pub(crate) async fn notify_channels_of_compaction(
 299→    state: &Arc<dyn ChatRuntime>,
 300→    session_key: &str,
 301→    outcome: &compaction_run::CompactionOutcome,
 302→    include_settings_hint: bool,
 303→) {
 304→    let targets = state.peek_channel_replies(session_key).await;
 305→    if targets.is_empty() {
 306→        return;
 307→    }
 308→
 309→    let Some(outbound) = state.channel_outbound() else {
 310→        return;
 311→    };
 312→
 313→    let message = format_channel_compaction_notice(outcome, include_settings_hint);
 314→    let mut tasks = Vec::with_capacity(targets.len());
 315→    for target in targets {
 316→        let outbound = Arc::clone(&outbound);
 317→        let message = message.clone();
 318→        let to = target.outbound_to().into_owned();
 319→        tasks.push(tokio::spawn(async move {
 320→            let reply_to = target.message_id.as_deref();
 321→            if let Err(e) = outbound
 322→                .send_text_silent(&target.account_id, &to, &message, reply_to)
 323→                .await
 324→            {
 325→                warn!(
 326→                    account_id = target.account_id,
 327→                    chat_id = target.chat_id,
 328→                    thread_id = target.thread_id.as_deref().unwrap_or("-"),
 329→                    "failed to send compaction notice to channel: {e}"
 330→                );
 331→            }
 332→        }));
 333→    }
 334→
 335→    for task in tasks {
 336→        if let Err(e) = task.await {
 337→            warn!(error = %e, "channel compaction notice task join failed");
 338→        }
 339→    }
 340→}
