 342→/// Send a short retry status update to pending channel targets without draining
 343→/// them. The final reply (or terminal error) will still use the same targets.
 344→pub(crate) async fn send_retry_status_to_channels(
 345→    state: &Arc<dyn ChatRuntime>,
 346→    session_key: &str,
 347→    error_obj: &Value,
 348→    retry_after: Duration,
 349→) {
 350→    let targets = state.peek_channel_replies(session_key).await;
 351→    if targets.is_empty() {
 352→        return;
 353→    }
 354→
 355→    let outbound = match state.channel_outbound() {
 356→        Some(o) => o,
 357→        None => return,
 358→    };
 359→
 360→    let message = format_channel_retry_message(error_obj, retry_after);
 361→    let mut tasks = Vec::with_capacity(targets.len());
 362→    for target in targets {
 363→        let outbound = Arc::clone(&outbound);
 364→        let message = message.clone();
 365→        let to = target.outbound_to().into_owned();
 366→        tasks.push(tokio::spawn(async move {
 367→            let reply_to = target.message_id.as_deref();
 368→            if let Err(e) = outbound
 369→                .send_text_silent(&target.account_id, &to, &message, reply_to)
 370→                .await
 371→            {
 372→                warn!(
 373→                    account_id = target.account_id,
 374→                    chat_id = target.chat_id,
 375→                    thread_id = target.thread_id.as_deref().unwrap_or("-"),
 376→                    "failed to send retry status to channel: {e}"
 377→                );
 378→            }
 379→        }));
 380→    }
 381→
 382→    for task in tasks {
 383→        if let Err(e) = task.await {
 384→            warn!(error = %e, "channel retry status task join failed");
 385→        }
 386→    }
