 389→/// Drain pending channel targets for a session and send a terminal error message.
 390→pub(crate) async fn deliver_channel_error(
 391→    state: &Arc<dyn ChatRuntime>,
 392→    session_key: &str,
 393→    error_obj: &Value,
 394→) {
 395→    let targets = state.drain_channel_replies(session_key).await;
 396→    let status_log = state.drain_channel_status_log(session_key).await;
 397→    if targets.is_empty() {
 398→        return;
 399→    }
 400→
 401→    let outbound = match state.channel_outbound() {
 402→        Some(o) => o,
 403→        None => return,
 404→    };
 405→
 406→    let error_text = format_channel_error_message(error_obj);
 407→    let logbook_html = format_logbook_html(&status_log);
 408→    let mut tasks = Vec::with_capacity(targets.len());
 409→    for target in targets {
 410→        let outbound = Arc::clone(&outbound);
 411→        let error_text = error_text.clone();
 412→        let logbook_html = logbook_html.clone();
 413→        let to = target.outbound_to().into_owned();
 414→        tasks.push(tokio::spawn(async move {
 415→            let reply_to = target.message_id.as_deref();
 416→            let send_result = if logbook_html.is_empty() {
 417→                outbound
 418→                    .send_text(&target.account_id, &to, &error_text, reply_to)
 419→                    .await
 420→            } else {
 421→                outbound
 422→                    .send_text_with_suffix(
 423→                        &target.account_id,
 424→                        &to,
 425→                        &error_text,
 426→                        &logbook_html,
 427→                        reply_to,
 428→                    )
 429→                    .await
 430→            };
 431→            if let Err(e) = send_result {
 432→                warn!(
 433→                    account_id = target.account_id,
 434→                    chat_id = target.chat_id,
 435→                    thread_id = target.thread_id.as_deref().unwrap_or("-"),
 436→                    "failed to send channel error reply: {e}"
 437→                );
 438→            }
 439→        }));
 440→    }
 441→
 442→    for task in tasks {
 443→        if let Err(e) = task.await {
 444→            warn!(error = %e, "channel error task join failed");
 445→        }
 446→    }
 447→}
