 449→async fn deliver_channel_replies_to_targets(
 450→    outbound: Arc<dyn moltis_channels::plugin::ChannelOutbound>,
 451→    targets: Vec<moltis_channels::ChannelReplyTarget>,
 452→    session_key: &str,
 453→    text: &str,
 454→    state: Arc<dyn ChatRuntime>,
 455→    desired_reply_medium: ReplyMedium,
 456→    status_log: Vec<String>,
 457→    streamed_target_keys: &HashSet<ChannelReplyTargetKey>,
 458→) {
 459→    let session_key = session_key.to_string();
 460→    let text = text.to_string();
 461→    let logbook_html = format_logbook_html(&status_log);
 462→    let mut tasks = Vec::with_capacity(targets.len());
 463→    for target in targets {
 464→        let outbound = Arc::clone(&outbound);
 465→        let state = Arc::clone(&state);
 466→        let session_key = session_key.clone();
 467→        let text = text.clone();
 468→        let logbook_html = logbook_html.clone();
 469→        // Text was already delivered via edit-in-place streaming — skip text
 470→        // caption/follow-up and only send the TTS voice audio.
 471→        let text_already_streamed =
 472→            streamed_target_keys.contains(&ChannelReplyTargetKey::from(&target));
 473→        let to = target.outbound_to().into_owned();
 474→        tasks.push(tokio::spawn(async move {
 475→            let tts_payload = match desired_reply_medium {
 476→                ReplyMedium::Voice => build_tts_payload(&state, &session_key, &target, &text).await,
 477→                ReplyMedium::Text => None,
 478→            };
 479→            let reply_to = target.message_id.as_deref();
 480→            match target.channel_type {
 481→                moltis_channels::ChannelType::Telegram => match tts_payload {
 482→                    Some(mut payload) => {
 483→                        let transcript = std::mem::take(&mut payload.text);
 484→
 485→                        if text_already_streamed {
 486→                            // Text was already streamed — send voice audio only.
 487→                            if let Err(e) = outbound
 488→                                .send_media(&target.account_id, &to, &payload, reply_to)
 489→                                .await
 490→                            {
 491→                                warn!(
 492→                                    account_id = target.account_id,
 493→                                    chat_id = target.chat_id,
 494→                                    thread_id = target.thread_id.as_deref().unwrap_or("-"),
 495→                                    "failed to send channel voice reply: {e}"
 496→                                );
 497→                            }
 498→                            // Send logbook as a follow-up if present.
 499→                            if !logbook_html.is_empty()
 500→                                && let Err(e) = outbound
 501→                                    .send_html(&target.account_id, &to, &logbook_html, None)
 502→                                    .await
 503→                            {
 504→                                warn!(
 505→                                    account_id = target.account_id,
 506→                                    chat_id = target.chat_id,
 507→                                    thread_id = target.thread_id.as_deref().unwrap_or("-"),
 508→                                    "failed to send logbook follow-up: {e}"
 509→                                );
 510→                            }
 511→                        } else if transcript.len()
 512→                            <= moltis_telegram::markdown::TELEGRAM_CAPTION_LIMIT
 513→                        {
 514→                            // Short transcript fits as a caption on the voice message.
 515→                            payload.text = transcript;
 516→                            if let Err(e) = outbound
 517→                                .send_media(&target.account_id, &to, &payload, reply_to)
 518→                                .await
 519→                            {
 520→                                warn!(
 521→                                    account_id = target.account_id,
 522→                                    chat_id = target.chat_id,
 523→                                    thread_id = target.thread_id.as_deref().unwrap_or("-"),
 524→                                    "failed to send channel voice reply: {e}"
 525→                                );
 526→                            }
 527→                            // Send logbook as a follow-up if present.
 528→                            if !logbook_html.is_empty()
 529→                                && let Err(e) = outbound
 530→                                    .send_html(&target.account_id, &to, &logbook_html, None)
 531→                                    .await
 532→                            {
 533→                                warn!(
 534→                                    account_id = target.account_id,
 535→                                    chat_id = target.chat_id,
 536→                                    thread_id = target.thread_id.as_deref().unwrap_or("-"),
 537→                                    "failed to send logbook follow-up: {e}"
 538→                                );
 539→                            }
 540→                        } else {
 541→                            // Transcript too long for a caption — send voice
 542→                            // without caption, then the full text as a follow-up.
 543→                            if let Err(e) = outbound
 544→                                .send_media(&target.account_id, &to, &payload, reply_to)
 545→                                .await
 546→                            {
 547→                                warn!(
 548→                                    account_id = target.account_id,
 549→                                    chat_id = target.chat_id,
 550→                                    thread_id = target.thread_id.as_deref().unwrap_or("-"),
 551→                                    "failed to send channel voice reply: {e}"
 552→                                );
 553→                            }
 554→                            let text_result = if logbook_html.is_empty() {
 555→                                outbound
 556→                                    .send_text(&target.account_id, &to, &transcript, None)
 557→                                    .await
 558→                            } else {
 559→                                outbound
 560→                                    .send_text_with_suffix(
 561→                                        &target.account_id,
 562→                                        &to,
 563→                                        &transcript,
 564→                                        &logbook_html,
 565→                                        None,
 566→                                    )
 567→                                    .await
 568→                            };
 569→                            if let Err(e) = text_result {
 570→                                warn!(
 571→                                    account_id = target.account_id,
 572→                                    chat_id = target.chat_id,
 573→                                    thread_id = target.thread_id.as_deref().unwrap_or("-"),
 574→                                    "failed to send transcript follow-up: {e}"
 575→                                );
 576→                            }
 577→                        }
 578→                    },
 579→                    None if text_already_streamed => {
 580→                        // TTS disabled/failed but text was already streamed —
 581→                        // only send logbook follow-up if present.
 582→                        if !logbook_html.is_empty()
 583→                            && let Err(e) = outbound
 584→                                .send_html(&target.account_id, &to, &logbook_html, None)
 585→                                .await
 586→                        {
 587→                            warn!(
 588→                                account_id = target.account_id,
 589→                                chat_id = target.chat_id,
 590→                                thread_id = target.thread_id.as_deref().unwrap_or("-"),
 591→                                "failed to send logbook follow-up: {e}"
 592→                            );
 593→                        }
 594→                    },
 595→                    None => {
 596→                        let result = if logbook_html.is_empty() {
 597→                            outbound
 598→                                .send_text(&target.account_id, &to, &text, reply_to)
 599→                                .await
 600→                        } else {
 601→                            outbound
 602→                                .send_text_with_suffix(
 603→                                    &target.account_id,
 604→                                    &to,
 605→                                    &text,
 606→                                    &logbook_html,
 607→                                    reply_to,
 608→                                )
 609→                                .await
 610→                        };
 611→                        if let Err(e) = result {
 612→                            warn!(
 613→                                account_id = target.account_id,
 614→                                chat_id = target.chat_id,
 615→                                thread_id = target.thread_id.as_deref().unwrap_or("-"),
 616→                                "failed to send channel reply: {e}"
 617→                            );
 618→                        }
 619→                    },
 620→                },
 621→                _ => match tts_payload {
 622→                    Some(payload) => {
 623→                        if let Err(e) = outbound
 624→                            .send_media(&target.account_id, &to, &payload, reply_to)
 625→                            .await
 626→                        {
 627→                            warn!(
 628→                                account_id = target.account_id,
 629→                                chat_id = target.chat_id,
 630→                                thread_id = target.thread_id.as_deref().unwrap_or("-"),
 631→                                "failed to send channel voice reply: {e}"
 632→                            );
 633→                        }
 634→                    },
 635→                    None if text_already_streamed => {
 636→                        // TTS disabled/failed but text was already streamed —
 637→                        // only send logbook follow-up if present.
 638→                        if !logbook_html.is_empty()
 639→                            && let Err(e) = outbound
 640→                                .send_html(&target.account_id, &to, &logbook_html, None)
 641→                                .await
 642→                        {
 643→                            warn!(
 644→                                account_id = target.account_id,
 645→                                chat_id = target.chat_id,
 646→                                thread_id = target.thread_id.as_deref().unwrap_or("-"),
 647→                                "failed to send logbook follow-up: {e}"
 648→                            );
 649→                        }
 650→                    },
 651→                    None => {
 652→                        let result = if logbook_html.is_empty() {
 653→                            outbound
 654→                                .send_text(&target.account_id, &to, &text, reply_to)
 655→                                .await
 656→                        } else {
 657→                            outbound
 658→                                .send_text_with_suffix(
 659→                                    &target.account_id,
 660→                                    &to,
 661→                                    &text,
 662→                                    &logbook_html,
 663→                                    reply_to,
 664→                                )
 665→                                .await
 666→                        };
 667→                        if let Err(e) = result {
 668→                            warn!(
 669→                                account_id = target.account_id,
 670→                                chat_id = target.chat_id,
 671→                                thread_id = target.thread_id.as_deref().unwrap_or("-"),
 672→                                "failed to send channel reply: {e}"
 673→                            );
 674→                        }
 675→                    },
 676→                },
 677→            }
 678→        }));
 679→    }
 680→
 681→    for task in tasks {
 682→        if let Err(e) = task.await {
 683→            warn!(error = %e, "channel reply task join failed");
 684→        }
 685→    }
 686→}
