 688→#[derive(Debug, Deserialize)]
 689→struct TtsStatusResponse {
 690→    enabled: bool,
 691→}
 692→
 693→#[derive(Debug, Serialize)]
 694→struct TtsConvertRequest<'a> {
 695→    text: &'a str,
 696→    format: &'a str,
 697→    #[serde(skip_serializing_if = "Option::is_none")]
 698→    provider: Option<String>,
 699→    #[serde(skip_serializing_if = "Option::is_none", rename = "voiceId")]
 700→    voice_id: Option<String>,
 701→    #[serde(skip_serializing_if = "Option::is_none")]
 702→    model: Option<String>,
 703→}
 704→
 705→#[derive(Debug, Deserialize)]
 706→#[serde(rename_all = "camelCase")]
 707→struct TtsConvertResponse {
 708→    audio: String,
 709→    #[serde(default)]
 710→    mime_type: Option<String>,
 711→}
 712→
 713→/// Generate TTS audio bytes for a web UI response.
 714→///
 715→/// Uses the session-level TTS override if configured, otherwise the global TTS
 716→/// config. Returns raw audio bytes (OGG format) on success, `None` if TTS is
 717→/// disabled or generation fails.
 718→pub(crate) async fn generate_tts_audio(
 719→    state: &Arc<dyn ChatRuntime>,
 720→    session_key: &str,
 721→    text: &str,
 722→) -> error::Result<Vec<u8>> {
 723→    use base64::Engine;
 724→
 725→    let tts_status = state
 726→        .tts_service()
 727→        .status()
 728→        .await
 729→        .map_err(error::Error::message)?;
 730→    let status: TtsStatusResponse = serde_json::from_value(tts_status)
 731→        .map_err(|_| error::Error::message("invalid tts.status response"))?;
 732→    if !status.enabled {
 733→        return Err(error::Error::message("TTS is disabled or not configured"));
 734→    }
 735→
 736→    // Layer 2: strip markdown/URLs the LLM may have included despite the prompt.
 737→    let text = moltis_voice::tts::sanitize_text_for_tts(text);
 738→    let text = text.trim();
 739→    if text.is_empty() {
 740→        return Err(error::Error::message("response has no speakable text"));
 741→    }
 742→
 743→    let (_, session_override) = state.tts_overrides(session_key, "").await;
 744→
 745→    let request = TtsConvertRequest {
 746→        text,
 747→        format: "ogg",
 748→        provider: session_override.as_ref().and_then(|o| o.provider.clone()),
 749→        voice_id: session_override.as_ref().and_then(|o| o.voice_id.clone()),
 750→        model: session_override.as_ref().and_then(|o| o.model.clone()),
 751→    };
 752→
 753→    let request_value = serde_json::to_value(request)
 754→        .map_err(|_| error::Error::message("failed to build tts.convert request"))?;
 755→    let tts_result = state
 756→        .tts_service()
 757→        .convert(request_value)
 758→        .await
 759→        .map_err(error::Error::message)?;
 760→
 761→    let response: TtsConvertResponse = serde_json::from_value(tts_result)
 762→        .map_err(|_| error::Error::message("invalid tts.convert response"))?;
 763→    base64::engine::general_purpose::STANDARD
 764→        .decode(&response.audio)
 765→        .map_err(|_| error::Error::message("invalid base64 audio returned by TTS provider"))
 766→}
 767→
 768→async fn build_tts_payload(
 769→    state: &Arc<dyn ChatRuntime>,
 770→    session_key: &str,
 771→    target: &moltis_channels::ChannelReplyTarget,
 772→    text: &str,
 773→) -> Option<moltis_common::types::ReplyPayload> {
 774→    use moltis_common::types::{MediaAttachment, ReplyPayload};
 775→
 776→    let tts_status = state.tts_service().status().await.ok()?;
 777→    let status: TtsStatusResponse = serde_json::from_value(tts_status).ok()?;
 778→    if !status.enabled {
 779→        return None;
 780→    }
 781→
 782→    // Strip markdown/URLs the LLM may have included — use sanitized text
 783→    // only for TTS conversion, but keep the original for the caption.
 784→    let sanitized = moltis_voice::tts::sanitize_text_for_tts(text);
 785→
 786→    let channel_key = format!("{}:{}", target.channel_type.as_str(), target.account_id);
 787→    let (channel_override, session_override) = state.tts_overrides(session_key, &channel_key).await;
 788→    let resolved = channel_override.or(session_override);
 789→
 790→    let request = TtsConvertRequest {
 791→        text: &sanitized,
 792→        format: "ogg",
 793→        provider: resolved.as_ref().and_then(|o| o.provider.clone()),
 794→        voice_id: resolved.as_ref().and_then(|o| o.voice_id.clone()),
 795→        model: resolved.as_ref().and_then(|o| o.model.clone()),
 796→    };
 797→
 798→    let tts_result = state
 799→        .tts_service()
 800→        .convert(serde_json::to_value(request).ok()?)
 801→        .await
 802→        .ok()?;
 803→
 804→    let response: TtsConvertResponse = serde_json::from_value(tts_result).ok()?;
 805→
 806→    let mime_type = response
 807→        .mime_type
 808→        .unwrap_or_else(|| "audio/ogg".to_string());
 809→
 810→    Some(ReplyPayload {
 811→        text: text.to_string(),
 812→        media: Some(MediaAttachment {
 813→            url: format!("data:{mime_type};base64,{}", response.audio),
 814→            mime_type,
 815→            filename: None,
 816→        }),
 817→        reply_to_id: None,
 818→        silent: false,
 819→    })
 820→}
