 822→/// Buffer a tool execution status into the channel status log for a session.
 823→/// The buffered entries are appended as a collapsible logbook when the final
 824→/// response is delivered, instead of being sent as separate messages.
 825→pub(crate) async fn send_tool_status_to_channels(
 826→    state: &Arc<dyn ChatRuntime>,
 827→    session_key: &str,
 828→    tool_name: &str,
 829→    arguments: &Value,
 830→) {
 831→    let targets = state.peek_channel_replies(session_key).await;
 832→    if targets.is_empty() {
 833→        return;
 834→    }
 835→
 836→    // Buffer the status message for the logbook
 837→    let message = format_tool_status_message(tool_name, arguments);
 838→    state.push_channel_status_log(session_key, message).await;
 839→}
 840→
 841→/// Buffer a tool error result into the channel status log for a session.
 842→/// Called from `ToolCallEnd` for failed tool calls only — success is implicit
 843→/// and does not need a separate log entry.
 844→pub(crate) async fn send_tool_result_to_channels(
 845→    state: &Arc<dyn ChatRuntime>,
 846→    session_key: &str,
 847→    tool_name: &str,
 848→    success: bool,
 849→    error: &Option<String>,
 850→    result: &Option<Value>,
 851→) {
 852→    if success {
 853→        return;
 854→    }
 855→    let targets = state.peek_channel_replies(session_key).await;
 856→    if targets.is_empty() {
 857→        return;
 858→    }
 859→
 860→    let message = format_tool_result_message(tool_name, error, result);
 861→    state.push_channel_status_log(session_key, message).await;
 862→}
 863→
 864→/// Format a human-readable error summary for a failed tool call.
 865→fn format_tool_result_message(
 866→    tool_name: &str,
 867→    error: &Option<String>,
 868→    result: &Option<Value>,
 869→) -> String {
 870→    let detail = match tool_name {
 871→        "exec" => {
 872→            let exit_code = result
 873→                .as_ref()
 874→                .and_then(|r| r.get("exitCode"))
 875→                .and_then(|v| v.as_i64());
 876→            let stderr = result
 877→                .as_ref()
 878→                .and_then(|r| r.get("stderr"))
 879→                .and_then(|v| v.as_str())
 880→                .unwrap_or_default();
 881→            let first_line = stderr.lines().next().unwrap_or_default();
 882→            let truncated = truncate_at_char_boundary(first_line, 120);
 883→            match exit_code {
 884→                Some(code) => {
 885→                    if truncated.is_empty() {
 886→                        format!("exit {code}")
 887→                    } else {
 888→                        format!("exit {code} — {truncated}")
 889→                    }
 890→                },
 891→                None => {
 892→                    if truncated.is_empty() {
 893→                        error
 894→                            .as_deref()
 895→                            .map(|e| truncate_at_char_boundary(e, 120).to_string())
 896→                            .unwrap_or_else(|| "failed".to_string())
 897→                    } else {
 898→                        truncated.to_string()
 899→                    }
 900→                },
 901→            }
 902→        },
 903→        _ => {
 904→            // Browser, web_fetch, web_search, and other tools: use error string.
 905→            error
 906→                .as_deref()
 907→                .map(|e| {
 908→                    let first_line = e.lines().next().unwrap_or_default();
 909→                    truncate_at_char_boundary(first_line, 120).to_string()
 910→                })
 911→                .unwrap_or_else(|| "failed".to_string())
 912→        },
 913→    };
 914→    format!("  ❌ {detail}")
 915→}
