 917→/// Format a human-readable tool execution message.
 918→fn format_tool_status_message(tool_name: &str, arguments: &Value) -> String {
 919→    match tool_name {
 920→        "browser" => {
 921→            let action = arguments
 922→                .get("action")
 923→                .and_then(|v| v.as_str())
 924→                .unwrap_or("unknown");
 925→            let url = arguments.get("url").and_then(|v| v.as_str());
 926→            let ref_ = arguments.get("ref_").and_then(|v| v.as_u64());
 927→
 928→            match action {
 929→                "navigate" => {
 930→                    if let Some(u) = url {
 931→                        format!("🌐 Navigating to {}", truncate_url(u))
 932→                    } else {
