 940→                        format!("👆 Clicking element #{}", r)
 941→                    } else {
 942→                        "👆 Clicking...".to_string()
 943→                    }
 944→                },
 945→                "type" => "⌨️ Typing...".to_string(),
 946→                "scroll" => "📜 Scrolling...".to_string(),
 947→                "evaluate" => "⚡ Running JavaScript...".to_string(),
 948→                "wait" => "⏳ Waiting for element...".to_string(),
 949→                "close" => "🚪 Closing browser...".to_string(),
 950→                _ => format!("🌐 Browser: {}", action),
 951→            }
 952→        },
 953→        "exec" => {
 954→            let command = arguments.get("command").and_then(|v| v.as_str());
 955→            if let Some(cmd) = command {
 956→                // Show first ~50 chars of command
 957→                let display_cmd = if cmd.len() > 50 {
