 965→            }
 966→        },
 967→        "web_fetch" => {
 968→            let url = arguments.get("url").and_then(|v| v.as_str());
 969→            if let Some(u) = url {
 970→                format!("🔗 Fetching {}", truncate_url(u))
 971→            } else {
 972→                "🔗 Fetching URL...".to_string()
 973→            }
 974→        },
 975→        "web_search" => {
 976→            let query = arguments.get("query").and_then(|v| v.as_str());
 977→            if let Some(q) = query {
 978→                let display_q = if q.len() > 40 {
 979→                    format!("{}...", truncate_at_char_boundary(q, 40))
 980→                } else {
 981→                    q.to_string()
 982→                };
 983→                format!("🔍 Searching: {}", display_q)
 984→            } else {
 985→                "🔍 Searching...".to_string()
 986→            }
 987→        },
 988→        "calc" => {
 989→            let expr = arguments
 990→                .get("expression")
 991→                .or_else(|| arguments.get("expr"))
 992→                .and_then(|v| v.as_str());
 993→            if let Some(expression) = expr {
 994→                let display = if expression.len() > 50 {
 995→                    format!("{}...", truncate_at_char_boundary(expression, 50))
 996→                } else {
 997→                    expression.to_string()
 998→                };
 999→                format!("🧮 Calculating: {}", display)
1000→            } else {
1001→                "🧮 Calculating...".to_string()
1002→            }
1003→        },
1004→        "memory_search" => "🧠 Searching memory...".to_string(),
1005→        "memory_delete" => "🧠 Removing memory snippet...".to_string(),
1006→        "memory_forget" => "🧠 Forgetting memory...".to_string(),
1007→        "memory_store" => "🧠 Storing to memory...".to_string(),
